use Drupal\Core\Cache\CacheableMetadata;
use Drupal\Core\Controller\ControllerBase;
use Drupal\Core\Link;
use Drupal\Core\Access\AccessResult;
use Drupal\Core\Session\AccountInterface;
use Drupal\node\NodeInterface;

final class RecentArticlesController extends ControllerBase {

  public function recentArticles(): array {
    $nids = $this->entityTypeManager()
      ->getStorage('node')
      ->getQuery()
      ->accessCheck(TRUE)
      ->condition('type', 'article')
      ->condition('status', NodeInterface::PUBLISHED)
      ->sort('created', 'DESC')
      ->range(0, 10)
      ->execute();

    $nodes = $this->entityTypeManager()
      ->getStorage('node')
      ->loadMultiple($nids);

    $items = [];
    $cacheability = new CacheableMetadata();
    $cacheability->addCacheTags(['node_list']);

    foreach ($nodes as $node) {
      $items[] = Link::fromTextAndUrl($node->label(), $node->toUrl())->toRenderable();
      $cacheability->addCacheableDependency($node);
    }

    $build = [
      '#type' => 'container',
      'title' => [
        '#type' => 'html_tag',
        '#tag' => 'h1',
        '#value' => $this->t('Recent articles'),
      ],
      'articles' => [
        '#theme' => 'item_list',
        '#items' => $items,
        '#empty' => $this->t('No published articles found.'),
      ],
    ];

    $cacheability->applyTo($build);

    return $build;
  }

  public function access(AccountInterface $account): AccessResult {
    return AccessResult::allowedIfHasPermission($account, 'access content');
  }

}
```

This returns a render array, not a `Response`, and attaches cacheability correctly:

- `user.permissions` is covered by the `AccessResult`.
- `node_list` invalidates when article listings change.
- Each loaded node is added as a cacheable dependency so title/URL changes invalidate the page too.

If your route already uses `_permission: 'access content'`, you can omit the `access()` method.
